// Get context for a specific compound in a specific category
export function getCategoryContext(compoundId, filterCategory) {
  const compoundCtx = CATEGORY_CONTEXT[compoundId];
  if (!compoundCtx) return null;

  const keyMap = {
    healing:      'healing',
    weight:       'weight',
    performance:  'performance',
    antiaging:    'antiaging',
    cognitive:    'cognitive',
    immune:       'immune',
    hormonal:     'hormonal',
    sexual:       'sexual',
    sleep:        'sleep',
    inflammation: 'inflammation',
    neuro:        'neuro',
  };

  const contextKey = keyMap[filterCategory];
  return contextKey ? compoundCtx[contextKey] || null : null;
}
